#include<bits/stdc++.h>
using namespace std;
struct node
{
    int x,y,op;
}a[200010];
int fa[200010],b[200010],n,m,k;
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
void merge(int x,int y)
{
    fa[find(x)]=find(y);
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        char s[21];
        scanf("%d%d%s",&a[i].x,&a[i].y,s+1);
        a[i].x--;
        if(s[1]=='e')
        {
            a[i].op=0;
        }
        else
        {
            a[i].op=1;
        }
        b[++k]=a[i].x;
        b[++k]=a[i].y;
    }
    sort(b+1,b+1+k);
    k=unique(b+1,b+1+k)-b-1;
    for(int i=1;i<=k*2;i++)
    {
        fa[i]=i;
    }
    for(int i=1;i<=m;i++)
    {
        a[i].x=lower_bound(b+1,b+1+k,a[i].x)-b;
        a[i].y=lower_bound(b+1,b+1+k,a[i].y)-b;
        if(a[i].op==1)
        {
            if(find(a[i].x)==find(a[i].y))
            {
                printf("%d",i-1);
                return 0;
            }
            merge(a[i].x+k,a[i].y);
            merge(a[i].x,a[i].y+k);
        }
        else
        {
            if(find(a[i].x)==find(a[i].y+k))
            {
                printf("%d",i-1);
                return 0;
            }
            merge(a[i].x,a[i].y);
            merge(a[i].x+k,a[i].y+k);
        }
    }
    printf("%d",m);
    return 0;
}
